code = """import json

# Read the Indianapolis businesses result file
result_file = locals()['var_functions.query_db:8']
if isinstance(result_file, str) and result_file.endswith('.json'):
    with open(result_file, 'r') as f:
        indianapolis_businesses = json.load(f)
else:
    indianapolis_businesses = locals()['var_functions.query_db:8']

# Extract business IDs and convert to business_ref format
business_refs = []
for business in indianapolis_businesses:
    business_id = business.get('business_id', '')
    if business_id.startswith('businessid_'):
        # Convert businessid_XXX to businessref_XXX
        ref_id = business_id.replace('businessid_', 'businessref_')
        business_refs.append(ref_id)

print(f"Found {len(indianapolis_businesses)} Indianapolis businesses")
print(f"Business refs: {business_refs}")

result = json.dumps(business_refs)
print('__RESULT__:')
print(result)"""

